.darma-loader-cssloaders-github-09 {
  display: inline-block;
  width: 130px;
  height: 10px;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--loader-color) 25%, var(--loader-secondary-color) 25%, var(--loader-secondary-color) 50%, var(--loader-color) 50%, var(--loader-color) 75%, var(--loader-secondary-color) 75%);
  background-size: 32px 100%; animation: darma-loader-cssloaders-github-09-progressStripe 0.97s linear infinite;
